import scala.xml._
import scala.xml.parsing.NoBindingFactoryAdapter

object ConfigParserService {
  def parseConfig(xmlString: String): Map[String, Any] = {
    // Load the XML string into an Elem
    val xml = XML.loadString(xmlString)
    
    // Extract settings from the XML
    def extractSettings(node: Node): Map[String, Any] = {
      node.child.collect {
        case elem: Elem =>
          elem.label -> (elem.child match {
            case Seq(textNode: Text) => textNode.text
            case children => children.map(extractSettings).foldLeft(Map.empty[String, Any]) { _ ++ _ }
          })
      }.toMap
    }
    
    extractSettings(xml)
  }

  def main(args: Array[String]): Unit = {
    val xmlConfig = """
      <config>
        <setting1>value1</setting1>
        <section1>
          <setting2>value2</setting2>
          <setting3>value3</setting3>
        </section1>
      </config>
    """
    
    val parsedConfig = parseConfig(xmlConfig)
    println(parsedConfig)
  }
}